using Microsoft.Build.Logging.StructuredLogger;
using Microsoft.Build.Logging;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = new List<(string project, string code, string message, string file, int line)>();
var warnings = new List<(string project, string code, string message, string file, int line)>();

build.VisitAllChildren<Error>(error =>
{
    var project = "";
    var parent = error.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    errors.Add((project, error.Code ?? "", error.Text ?? "", error.File ?? "", error.LineNumber));
});

build.VisitAllChildren<Warning>(warning =>
{
    var project = "";
    var parent = warning.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    warnings.Add((project, warning.Code ?? "", warning.Text ?? "", warning.File ?? "", warning.LineNumber));
});

Console.WriteLine("=== ERRORS ===");
foreach (var e in errors)
{
    Console.WriteLine($"[{e.project}] {e.code}: {e.message}");
    Console.WriteLine($"  File: {e.file}, Line: {e.line}");
}

Console.WriteLine($"\nTotal errors: {errors.Count}");
Console.WriteLine($"\n=== WARNINGS ===");
foreach (var w in warnings)
{
    Console.WriteLine($"[{w.project}] {w.code}: {w.message}");
    Console.WriteLine($"  File: {w.file}, Line: {w.line}");
}
Console.WriteLine($"\nTotal warnings: {warnings.Count}");

// Show build result per project
Console.WriteLine("\n=== PROJECT RESULTS ===");
