using Microsoft.Build.Logging.StructuredLogger;
using System;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Dump the tree to find structure
void DumpTree(BaseNode node, int depth = 0, int maxDepth = 6)
{
    if (depth > maxDepth) return;
    var prefix = new string(' ', depth * 2);
    var text = node.ToString();

    // Only print interesting things
    bool isError = node is Error;
    bool isWarning = node is Warning;
    bool isBuildFailed = text?.Contains("failed") == true || text?.Contains("Failed") == true;
    bool isCompile = node is Task t && t.Name == "Csc";

    if (isError || isWarning || isBuildFailed || isCompile || depth < 3)
    {
        Console.WriteLine($"{prefix}[{node.GetType().Name}] {text}");
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn)
                DumpTree(bn, depth + 1, maxDepth);
        }
    }
}

