using Microsoft.Build.Logging.StructuredLogger;
using System;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Find all errors with full context
Console.WriteLine("=== ALL ERRORS (with project context) ===\n");
build.VisitAllChildren<Error>(error =>
{
    var projectChain = new System.Collections.Generic.List<string>();
    var parent = error.Parent;
    string targetName = "";
    string taskName = "";
    while (parent != null)
    {
        if (parent is Project p) projectChain.Add(p.Name);
        if (parent is Target tgt && targetName == "") targetName = tgt.Name;
        if (parent is Task tk && taskName == "") taskName = tk.Name;
        parent = (parent as TreeNode)?.Parent;
    }

    Console.WriteLine($"Error Code: {error.Code}");
    Console.WriteLine($"Message:    {error.Text}");
    Console.WriteLine($"File:       {error.File}");
    Console.WriteLine($"Line:       {error.LineNumber}, Col: {error.ColumnNumber}");
    Console.WriteLine($"Project:    {string.Join(" -> ", projectChain)}");
    Console.WriteLine($"Target:     {targetName}");
    Console.WriteLine($"Task:       {taskName}");
    Console.WriteLine();
});

// Find all projects that failed
Console.WriteLine("=== FAILED PROJECTS ===\n");
build.VisitAllChildren<Project>(p =>
{
    // Check if this project has any error children
    bool hasErrors = false;
    p.VisitAllChildren<Error>(e => hasErrors = true);

    // Check for "Build FAILED" messages
    bool buildFailed = false;
    p.VisitAllChildren<Message>(m =>
    {
        if (m.Text?.Contains("Build FAILED") == true) buildFailed = true;
    });

    if (hasErrors || buildFailed)
    {
        Console.WriteLine($"Project: {p.Name}");
        Console.WriteLine($"  File: {p.SourceFilePath}");
        Console.WriteLine($"  Has errors: {hasErrors}");
        Console.WriteLine();
    }
});

// Show dependency chain (project references)
Console.WriteLine("=== CSC COMMAND LINES ===\n");
build.VisitAllChildren<Task>(task =>
{
    if (task.Name == "Csc")
    {
        var project = "";
        var parent = task.Parent;
        while (parent != null)
        {
            if (parent is Project p) { project = p.Name; break; }
            parent = (parent as TreeNode)?.Parent;
        }

        // Look for CommandLineArguments
        task.VisitAllChildren<Property>(prop =>
        {
            if (prop.Name == "CommandLineArguments")
            {
                // Extract just the /reference: lines
                var lines = prop.Value?.Split('\n') ?? Array.Empty<string>();
                Console.WriteLine($"[{project}] Csc references:");
                foreach (var line in lines)
                {
                    var trimmed = line.Trim();
                    if (trimmed.StartsWith("/reference:") || trimmed.StartsWith("-reference:"))
                        Console.WriteLine($"  {trimmed}");
                }
                Console.WriteLine();
            }
        });
    }
});
